import React, { useState } from 'react';
import { Send } from 'lucide-react';

const initialForm = {
  senderName: '',
  receiverName: '',
  sourceCity: '',
  destinationCity: '',
  weightKg: '',
  costInr: '',
  expectedDelivery: '',
};

export default function RegisterParcel({ onSubmit, isLoading }) {
  const [form, setForm] = useState(initialForm);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setForm((prev) => ({ ...prev, [name]: value }));
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    onSubmit(form, () => setForm(initialForm));
  };

  return (
    <div className="card shadow-sm border-0">
      <div className="card-body p-4">
        <h2 className="h4 mb-4">Register Parcel</h2>
        <form onSubmit={handleSubmit} className="row g-3">
          <Input label="Sender Name" name="senderName" value={form.senderName} onChange={handleChange} />
          <Input label="Receiver Name" name="receiverName" value={form.receiverName} onChange={handleChange} />
          <Input label="Source City" name="sourceCity" value={form.sourceCity} onChange={handleChange} />
          <Input label="Destination City" name="destinationCity" value={form.destinationCity} onChange={handleChange} />
          <Input label="Weight (kg)" name="weightKg" value={form.weightKg} onChange={handleChange} type="number" step="0.1" />
          <Input label="Cost (₹)" name="costInr" value={form.costInr} onChange={handleChange} type="number" />
          <Input label="Expected Delivery (optional)" name="expectedDelivery" value={form.expectedDelivery} onChange={handleChange} />
          <div className="col-12">
            <button type="submit" className="btn btn-primary d-flex align-items-center gap-2" disabled={isLoading}>
              <Send size={18} />
              {isLoading ? 'Saving...' : 'Register Parcel'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

function Input({ label, name, value, onChange, type = 'text', step }) {
  return (
    <div className="col-md-6">
      <label className="form-label">{label}</label>
      <input
        type={type}
        step={step}
        className="form-control"
        name={name}
        value={value}
        onChange={onChange}
        required={name !== 'expectedDelivery'}
      />
    </div>
  );
}
